# Let me write a small C# program to parse the binlog properly
mkdir -p /tmp/binlog-reader && cat > /tmp/binlog-reader/Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild("/tmp/sv-21455b3a76d64270905f1207950b1a6d/build.binlog");

Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = build.FindChildrenRecursive<Error>().ToList();
Console.WriteLine($"Total Errors: {errors.Count}");
Console.WriteLine();

// Group errors by project
var errorsByProject = errors.GroupBy(e => {
    var node = e.Parent;
    while (node != null) {
        if (node is Project p) return p.Name;
        if (node is Target t) {
            var pp = t.Parent;
            while (pp != null) {
                if (pp is Project proj) return proj.Name;
                pp = (pp as TreeNode)?.Parent;
            }
        }
        node = (node as TreeNode)?.Parent;
    }
    return "Unknown";
}).OrderBy(g => g.Key);

foreach (var group in errorsByProject)
{
    Console.WriteLine($"=== Project: {group.Key} ===");
    foreach (var error in group)
    {
        Console.WriteLine($"  [{error.Code}] {error.File}({error.LineNumber},{error.ColumnNumber}): {error.Text}");
    }
    Console.WriteLine();
}

// Check for project build failures (dependency failures)
Console.WriteLine("=== Project Build Results ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects.Where(p => !p.Succeeded))
{
    Console.WriteLine($"  FAILED: {p.Name} (ProjectFile: {p.ProjectFile})");
}
EOF

