using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("/tmp/sv-21455b3a76d64270905f1207950b1a6d/build.binlog");

// Check all projects and their dependencies
var projects = build.FindChildrenRecursive<Project>().ToList();
Console.WriteLine("=== All Projects in Solution ===");
foreach (var p in projects.Where(p => p.ProjectFile?.EndsWith(".csproj") == true))
{
    Console.WriteLine($"  {p.Name} -> {p.ProjectFile}");
}

// Look for MSB3202 or dependency errors
Console.WriteLine("\n=== All Warnings (filtered) ===");
var warnings = build.FindChildrenRecursive<Warning>().ToList();
foreach (var w in warnings.Where(w => w.Code == "MSB3202" || w.Code == "NU1101" || w.Code == "NU3001" || w.Text?.Contains("could not be resolved") == true || w.Text?.Contains("dependency") == true))
{
    Console.WriteLine($"  [{w.Code}] {w.Text}");
}

// Look for restore failures
Console.WriteLine("\n=== NuGet/Restore related messages ===");
var allMessages = build.FindChildrenRecursive<Message>().Where(m => 
    m.Text?.Contains("Newtonsoft") == true || 
    m.Text?.Contains("PackageReference") == true ||
    m.Text?.Contains("restore") == true
).Take(30).ToList();
foreach (var m in allMessages)
{
    Console.WriteLine($"  {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
}

// Check if there are projects that failed due to dependency on Services
Console.WriteLine("\n=== Projects referencing Services ===");
var allMsgs = build.FindChildrenRecursive<Message>().Where(m => m.Text?.Contains("Services") == true).Take(20).ToList();
foreach (var m in allMsgs)
{
    if (m.Text?.Contains("Project") == true || m.Text?.Contains("reference") == true || m.Text?.Contains("Reference") == true)
        Console.WriteLine($"  {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
}
EOF
